public class Solution implements Runnable{
    private BufferedReader reader;
    private BufferedWriter writer;
    static int[] dx={-1,-1,-1,0,0,0,1,1,1};
    static int[] dy={-1,0,1,-1,0,1,-1,0,1};
    public static final int MAX = 5 + 10;
    public static char maze[][];
    public static boolean vis[][];
    public static String string1,string2;
    public static int len1,len2;


    public static void dfs(int x,int y){
        if (x < 0 || y < 0) {
            return ;
        }else if (x == len1 - 1 && y == len2 - 1) {
        	return ;
        }
        vis[x][y]=true;
        for (int i = 0; i <= 8; i++) {
            int tx = x + dx[i];
            int ty = y + dy[i];
            if (tx < len1 && ty < len2 && !vis[tx][ty]) {
                dfs(tx, ty);
            }
        }
    }
    @Override
    public void run() throws IOException {
        // TODO Auto-generated method stub
        reader=new BufferedReader(new InputStreamReader(System.in));
        writer=new BufferedWriter(new OutputStreamWriter(System.out));
        string1 = reader.readLine().trim();
        string2 = reader.readLine().trim();
        len1 = string1.length();
        len2 = string2.length();
        maze = new char[MAX][MAX];
        vis = new boolean[MAX][MAX];
        int tempX = 5 ,tempY= 5;
        for (int i = 1; i <= len1; ++i ) {
            Arrays.fill(vis[i], false);
        }
        for (int i = 0; i < len1; ++i) {
            maze[i].getClass();
        }
        for (int i = 1; i <= len1; i++) {
            for (int j = 1; j <= len2; j++) {
            	maze[i][j] = string2.charAt(i-1);
            }
        }
        dfs(tempX,tempY);
        write(writer,"Yes");
        writer.flush();
    }
    public static void main(String [] args) throws Exception{
       new Solution().run();
	}
}

issue_description:
The code:
function name() {
   var arguments = Array.prototype.slice.call(arguments, 0);
}

gets compiled to:
function name(){ var c=Array.prototype.slice.call(c,0); }

Thanks to tescosquirrel for the report.

